#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int networkDelayTime(vector<vector<int>>& times, int n, int k) {
        vector<vector<pair<int,int>>> adj(n+1);
        for (auto &e: times) {
            int u=e[0], v=e[1], w=e[2];
            adj[u].push_back({v,w});
        }
        const long long INF = 4e18;
        vector<long long> dist(n+1, INF);
        dist[k]=0;
        using P = pair<long long,int>;
        priority_queue<P, vector<P>, greater<P>> pq;
        pq.push({0,k});
        while(!pq.empty()){
            auto _tmp_binding_0 = pq.top(); auto d = _tmp_binding_0.first; auto u = _tmp_binding_0.second; pq.pop();
            if(d!=dist[u]) continue;
            for(auto &pr: adj[u]){
                int v=pr.first; int w=pr.second;
                long long nd=d+w;
                if(nd<dist[v]){
                    dist[v]=nd;
                    pq.push({nd,v});
                }
            }
        }
        long long ans=0;
        for(int i=1;i<=n;i++){
            if(dist[i]==INF) return -1;
            ans=max(ans, dist[i]);
        }
        return (int)ans;
    }
};

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n,m,edge_cnt;
    if(!(cin>>n)) return 0;
    cin>>m; // read but not used separately
    cin>>edge_cnt;
    vector<vector<int>> times;
    times.reserve(edge_cnt);
    for(int i=0;i<edge_cnt;i++){
        int u,v,w;cin>>u>>v>>w;
        times.push_back({u,v,w});
    }
    int k;cin>>k;
    Solution sol;
    int ans=sol.networkDelayTime(times,n,k);
    cout<<ans<<"\n";
    return 0;
}
